import pandas as pdimport matplotlib.pyplot as pltimport seaborn as snsdata = pd.read_csv("Physically_Coupled_Engine_Dataset.csv")print(data.shape)print(data.columns)print(data.head(5))print(data.describe().apply(lambda s: s.apply('{0:.5f}'.format)))#chekcing for the missing valuesmissingValues = data.isnull()#then count the number of misisng valuesmissingCounts = missingValues.sum()print("missing cells each column is.. \n", missingCounts)hasMissingValues = missingValues.any().any()print (hasMissingValues)#now onto plotting the distributionfig, axes = plt.subplots(1, 8, figsize=(14,3))data.hist(ax=axes) #create histograms for all colplt.tight_layout()data_subset = data.iloc[:, 0] # data truncationfig1, ax = plt.subplots()sns.boxplot(data=data_subset, ax=ax)sns.stripplot(data=data_subset, color = 'red', size = 4, jitter = True, ax=ax)plt.ylabel('velocity')plt.show()Q1 = data.quantile(0.25)Q3 = data.quantile(0.75)IQR = Q3 -Q1lowerBound = Q1 - (1.5 * IQR)upperBound = Q3 + (1.5 * IQR) # i mean this is an easy statistics init#focusing on the 3rd collumn,lowerBoundThirdCol = lowerBound[0]upperBoundThirdCol = upperBound[0]outliers = data[(data['Exit Velocity (m/s)'].values < lowerBoundThirdCol) |                 (data['Exit Velocity (m/s)'].values > upperBoundThirdCol)] # and this is easy mathsoutliers = outliers.iloc[:, [0, -1]] # removing all column..? why? print(outliers)# pearson corr is a very good tool to determine the correleation between the datsets # and identify the trends/commonness in the dataframe + dependency etccorrelationMatrix = data.corr()plt.figure(figsize=(8,6))sns.heatmap(correlationMatrix, annot=True, linewidths=0.5)ax.tick_params(axis='x', labelrotation=45)plt.title('Correlation Matrix Heatmap')plt.show()fig, ax = plt.subplots(1,8,figsize=(27,6))for i, col in enumerate(data.columns[1:]):    #random_df.plot(kind='scatter', x=col, y='MEDV', ax=ax[i])    sns.regplot(x=data[col], y=data["Exit Velocity (m/s)"], ax=ax[i])fig.suptitle('my scatter plots')fig.tight_layout()fig.subplots_adjust(top=0.95)plt.show()plt.clf()plt.close()